-- Table de statuts pour les articles
CREATE TABLE article_status (
    id INT AUTO_INCREMENT PRIMARY KEY,
    code VARCHAR(50) UNIQUE NOT NULL,
    libelle VARCHAR(100) NOT NULL
) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

INSERT INTO article_status (code, libelle)
VALUES
('published', 'Publie'),
('deleted', 'Supprime');

-- Création de la table pour les articles
CREATE TABLE articles (
    id INT AUTO_INCREMENT PRIMARY KEY,
    titre_h1 VARCHAR(255) NOT NULL,            -- Pour le SEO
    url_slug VARCHAR(255) UNIQUE NOT NULL,     -- Pour l'URL rewriting
    contenu_html TEXT,                         -- Ce qui viendra de TinyMCE
    image_url VARCHAR(255),
    image_alt VARCHAR(255),                    -- Pour le SEO
    meta_description VARCHAR(160),             -- Pour les balises méta
    article_status_id INT NOT NULL DEFAULT 1,
    date_creation TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_articles_status FOREIGN KEY (article_status_id) REFERENCES article_status(id)
) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

-- Donnees de test pour l'index
INSERT INTO articles (titre_h1, url_slug, contenu_html, image_url, image_alt, meta_description, article_status_id)
VALUES
('Briefing du matin: deplacements et securite', 'briefing-du-matin-deplacements-et-securite', '<h2>Contexte general</h2><p>La journee a commence par un briefing interservices de 06h30 afin d''actualiser la carte des deplacements internes et d''identifier les zones a risque eleve. Les equipes logistiques, medicales et redactionnelles ont partage leurs observations de terrain collecte es pendant la nuit, notamment sur l''etat des routes secondaires, la disponibilite des points de passage et la fluidite des controles.</p><p>Le principal enjeu de cette premiere reunion etait de maintenir la continuite des operations sans exposer inutilement les equipes aux incidents locaux. Les responsables de secteur ont confirme que les itinera ires principaux restent praticables, mais que deux corridors habituellement utilises le matin sont desormais soumis a des horaires de passage stricts. Cette contrainte impose une planification plus fine et une meilleure synchronisation entre transport et communication.</p><h2>Points de vigilance par zone</h2><p>Au nord, la situation est restee globalement stable, avec quelques ralentissements autour des checkpoints temporaires. A l''ouest, les deplacements restent possibles mais exigent des detours de 20 a 35 minutes selon les tranches horaires. A l''est, les remont ees de terrain signalent une hausse des controles documentaires, ce qui allonge les files d''attente et peut retarder l''arrivee des convois humanitaires ou techniques.</p><p>Dans le centre, la priorite a ete donnee aux missions essentielles: transfert medical, ravitaillement en carburant, et maintenance des infrastructures critiques. Les deplacements non urgents ont ete reportes pour limiter l''encombrement et conserver une marge de securite en cas de degradation rapide de la situation. Cette priorisation est revue toutes les quatre heures pour integrer les nouvelles informations.</p><h2>Mesures operationnelles adoptees</h2><p>Trois mesures ont ete validees au cours du briefing. Premiere mesure: mise en place d''un systeme de validation des trajets en deux niveaux, avec confirmation locale puis validation centrale avant depart. Deuxieme mesure: renforcement du suivi temps reel via une cellule de coordination dediee qui recoupe radio, messagerie securisee et alertes terrain. Troisieme mesure: standardisation d''un protocole de repli pour tous les vehicules engages au-dela des zones vertes.</p><p>Les responsables securite insistent sur l''importance de la discipline de communication: signaler les departs, indiquer les points de passage franchis, puis confirmer l''arrivee a destination. En cas de silence prolonge, une procedure d''escalade est declenchee automatiquement pour verifier la situation de l''equipe concernee. Ce protocole, deja teste la semaine precedente, a permis de reduire significativement le temps de reaction en cas d''incident.</p><h2>Perspectives pour les prochaines heures</h2><p>Les tendances observees ce matin montrent une situation encore mouvante mais contenue. Si les conditions restent stables, les equipes pourront reprendre progressivement certaines rotations suspendues depuis 48 heures. Dans le cas contraire, le scenario degrade prevoit un recentrage sur les missions vitales et une reduction du volume de deplacements. Un nouveau point de situation est prevu a midi, puis en fin d''apres-midi.</p><p>Pour les lecteurs, cela signifie que le rythme des mises a jour restera soutenu, avec un accent particulier sur les informations verifiees et contextualisees. L''objectif est de fournir une vision claire des contraintes de terrain, sans dramatisation inutile, afin d''aider chacun a comprendre les decisions prises par les equipes engagees.</p>', 'assets/img/uploads/briefing-matin.jpg', 'Carte des deplacements et checkpoints', 'Point rapide sur la securite et les deplacements internes.', 1),
('Chronologie: la semaine en 5 dates', 'chronologie-la-semaine-en-5-dates', '<h2>Pourquoi cette chronologie compte</h2><p>Comprendre une semaine intense ne consiste pas a empiler des faits: il faut relier les decisions, les reactions et les consequences. Cette chronologie en cinq dates propose une lecture structur ee des evenements qui ont marque la periode recente. Chaque etape explique non seulement ce qui s''est passe, mais aussi pourquoi ce moment a change la suite.</p><p>Les informations presentees ici sont issues de sources ouvertes, de communiques institutionnels et de temoignages recoupes. L''objectif n''est pas d''epuiser tous les details, mais d''offrir une base solide pour suivre les evolutions en cours et replacer l''actualite du jour dans son contexte.</p><h2>Date 1 - Lundi: le signal initial</h2><p>Le debut de semaine a ete marque par une serie d''annonces administratives qui ont redessine le cadre des operations. Plusieurs acteurs locaux ont interprete ces annonces comme un changement de posture, ce qui a immediatement influence les deplacements et les priorites logistiques. Les reactions ont ete rapides mais heterogenes selon les secteurs.</p><p>Cette premiere date est essentielle car elle introduit les contraintes qui vont peser sur tout le reste de la semaine: validation renforcee des flux, coordination plus centralisee, et reevaluation des missions considerees comme non essentielles.</p><h2>Date 2 - Mardi: ajustements de terrain</h2><p>Des le lendemain, les equipes ont commence a appliquer des plans alternatifs pour maintenir les activites critiques. Les organisations presentes sur place ont privilegie des itinera ires secondaires et adapte les horaires de circulation. Ces ajustements ont permis d''eviter une rupture brutale, mais au prix de delais supplementaires et d''une pression accrue sur les points de passage encore ouverts.</p><p>Cette phase d''adaptation montre que les marges de manoeuvre existent, a condition d''avoir une coordination fine et des informations actualisees en continu. Elle souligne aussi les limites d''une strategie reactive lorsque les contraintes evoluent rapidement.</p><h2>Date 3 - Jeudi: escalation des tensions locales</h2><p>Le troisieme tournant intervient avec plusieurs incidents localises qui ont force une suspension temporaire de certaines rotations. Meme si leur impact geographique est reste limite, leur effet psychologique a ete important: prudence accrue des operateurs, reports de mission, et concentration des moyens sur les zones jugees prioritaires.</p><p>Les observateurs s''accordent a dire que cette date a agi comme un test de resilience pour les dispositifs mis en place en debut de semaine. Les equipes ayant anticipe des scenarios de repli ont pu redemarrer plus vite, tandis que les structures moins preparees ont accuse un retard notable.</p><h2>Date 4 - Vendredi: reprise partielle et reorganisation</h2><p>Apres les perturbations, la journee de vendredi a ete celle d''une reprise progressive. Les activites ont redemarre par paliers, en donnant la priorite aux besoins immediats: approvisionnement, interventions medicales, et circulation d''informations verifiees. Cette reprise n''a pas signifie un retour a la normale, mais plutot une nouvelle phase de stabilisation.</p><p>La reorganisation interne a egalement gagne en maturite: clarification des responsabilites, circuits de validation simplifies, et renforcement des points de contact entre equipes mobiles et cellules de coordination.</p><h2>Date 5 - Dimanche: bilan provisoire et cap a venir</h2><p>En fin de semaine, les principaux acteurs ont publie un bilan provisoire mettant en avant deux constats. Premier constat: les mecanismes de coordination ont globalement tenu, malgre des fragilites persistantes. Second constat: la qualite de l''information partagee reste le facteur cle pour limiter les erreurs de decision et anticiper les blocages.</p><p>La semaine suivante s''ouvre donc sur un double objectif: consolider les protocoles qui ont fait leurs preuves et corriger les points faibles identifies, notamment sur la rapidite de circulation des alertes. Cette lecture chronologique permet de comprendre que les evenements ne sont pas isoles, mais s''inscrivent dans une dynamique continue.</p>', 'assets/img/uploads/chronologie-semaine.jpg', 'Frise chronologique de la semaine', 'Cinq dates cles pour comprendre la semaine en un coup d''oeil.', 1),
('Sources et methodologie de verification', 'sources-et-methodologie-de-verification', '<h2>Notre approche editoriale</h2><p>Publier vite ne suffit pas: dans un contexte sensible, la valeur d''un article repose sur la fiabilite des informations qu''il contient. Notre methode de verification combine des sources ouvertes, des confirmations institutionnelles et des temoignages de terrain recoupes. Chaque element est evalue selon son origine, sa coherence avec les faits deja etablis et sa capacite a etre confirme de maniere independante.</p><p>Cette demarche vise a reduire le risque de propagation d''erreurs, de rumeurs ou de contenus manipules. Elle implique parfois de retarder une publication de quelques heures pour obtenir une confirmation supplementaire. Ce choix editorial privilegie la precision plutot que la vitesse brute.</p><h2>Etape 1 - Collecte multi-sources</h2><p>La premiere etape consiste a reunir des donnees provenant de plusieurs canaux: communiques officiels, agences de presse reconnues, bases de donnees publiques, images satellites ouvertes, et temoignages directs transmis par des contacts identifies. A ce stade, aucune information n''est consideree comme definitive.</p><p>Les contenus visuels (photos, videos) font l''objet d''une verification technique preliminaire: metadonnees disponibles, coherence des ombres et de la meteorologie, rep eres geographiques visibles, et comparaison avec des archives anterieures. Les documents textuels sont examines pour detecter les incoherences de date, de vocabulaire ou de format.</p><h2>Etape 2 - Recoupement et qualification</h2><p>Chaque affirmation est classee dans l''une des categories suivantes: confirmee, probable, non confirmee, ou contestee. Pour passer au statut confirmee, une information doit etre validee par au moins deux sources independantes de nature differente, par exemple un acteur institutionnel et un temoin de terrain, ou une source ouverte et un document officiel.</p><p>Lorsque les sources divergent, nous indiquons explicitement l''incertitude au lieu de trancher artificiellement. Cette transparence permet au lecteur de comprendre le niveau de confiance associe a chaque passage de l''article. Les points encore en verification sont suivis dans un tableau horodate afin de tracer les evolutions.</p><h2>Etape 3 - Validation redactionnelle finale</h2><p>Avant publication, un second journaliste ou editeur relit l''article pour verifier la chaine de preuves. Cette relecture ne se limite pas a la forme: elle controle la fidelite des citations, la precision des dates, et la proportion entre faits etablis et elements d''analyse. Les formulations ambigu es sont reformulees pour eviter toute interpretation trompeuse.</p><p>Nous appliquons egalement une regle de prudence sur les contenus potentiellement sensibles: pas de details pouvant mettre en danger des personnes, pas d''informations tactiques non indispensables a la comprehension, et anonymisation systematique des temoins non publics.</p><h2>Mise a jour et droit de correction</h2><p>Un article publie n''est pas fige. Si de nouveaux faits fiables apparaissent, nous mettons a jour le contenu en conservant une trace claire des modifications majeures. En cas d''erreur, la correction est explicite et horodatee, avec une note indiquant ce qui a ete rectifie. Cette pratique renforce la confiance et permet au lecteur de suivre l''evolution de l''information.</p><p>Notre objectif final est simple: fournir des contenus utiles, comprehensibles et verifiables. Dans un environnement ou la desinformation circule vite, la methodologie n''est pas un luxe editorial, c''est une condition de credibilite.</p>', 'assets/img/uploads/sources-methodologie.jpg', 'Table de verification et sources', 'Comment les informations sont verifiees et recoupees.', 1);
